import axios from 'axios'
import store from '@/store'
import { MessageBox } from 'element-ui'

const service = axios.create({
  baseURL: '/api', // 使用 vue.config.js 的代理
  timeout: 5000
})

// 自定义错误类，避免被 webpack-dev-server 错误覆盖层捕获
class HandledError extends Error {
  constructor(message) {
    super(message)
    this.name = 'HandledError'
    this.handled = true
  }
}

// 请求拦截器
service.interceptors.request.use(
  config => {
    if (store.state.token) {
      config.headers['Authorization'] = 'Bearer ' + store.state.token
    }
    return config
  },
  error => {
    return Promise.reject(error)
  }
)

// 响应拦截器
service.interceptors.response.use(
  response => {
    const res = response.data
    // 假设后端返回格式 { code: 200, message: '成功', data: ... }
    if (res.code !== 200) {
      if (res.code === 401) {
        store.commit('LOGOUT')
        MessageBox.confirm('您还未登录，是否前往登录页面？', '提示', {
          confirmButtonText: '去登录',
          cancelButtonText: '取消',
          type: 'warning'
        }).then(() => {
          window.location.href = '/login'
        }).catch(() => {})
        return Promise.reject(new HandledError('请先登录'))
      }
      MessageBox.alert(res.message || '操作失败', '提示', {
        confirmButtonText: '确定',
        type: 'warning'
      }).catch(() => {})
      return Promise.reject(new HandledError(res.message || '操作失败'))
    } else {
      return res.data
    }
  },
  error => {
    if (error.handled) {
      return Promise.reject(error)
    }
    if (error.response && error.response.status === 401) {
      store.commit('LOGOUT')
      MessageBox.confirm('您还未登录，是否前往登录页面？', '提示', {
        confirmButtonText: '去登录',
        cancelButtonText: '取消',
        type: 'warning'
      }).then(() => {
        window.location.href = '/login'
      }).catch(() => {})
      return Promise.reject(new HandledError('请先登录'))
    }
    let errorMsg = error.message
    if (error.response && error.response.data && error.response.data.message) {
      errorMsg = error.response.data.message
    }
    MessageBox.alert(errorMsg, '系统异常', {
      confirmButtonText: '我知道了',
      type: 'error'
    }).catch(() => {})
    return Promise.reject(new HandledError(errorMsg))
  }
)

export default service
